page_settings.custom_css:
/* ===== WRAPPER ===== */
#btn .elementor-button-content-wrapper, .btn .elementor-button-content-wrapper{
    display:flex;
    align-items:center;
    gap:20px;
}

/* ===== TEXTO ===== */
#btn .elementor-button-text, .btn .elementor-button-text{
    padding:22px 30px;
    padding-right:30px; /* base */
    border-radius:100px;
    background:linear-gradient(135deg, #1e6bff, #3fa9ff);
    color:#fff;
    font-weight:600;
    transition:padding 0.3s ease;
}

/* ===== ÍCONE ===== */
#btn .elementor-button-icon, .btn .elementor-button-icon{
    display:flex;
    align-items:center;
    justify-content:center;
    padding:22px;
    border-radius:100px;
    background:linear-gradient(135deg, #1e6bff, #3fa9ff);
    color:#fff;
    transition:transform 0.3s ease;
}

/* ===== HOVER ===== */
#btn:hover .elementor-button-icon, .btn .elementor-button:hover .elementor-button-icon{
    transform:translateX(-72px);
    background:transparent;
    transition:transform 0.16s ease;
}

#btn:hover .elementor-button-text, .btn .elementor-button:hover .elementor-button-text{
    padding-right:70px;
}

@media (max-width: 768px) {
#btn .elementor-button-text, .btn .elementor-button-text{
    padding:16px 20px;
}

#btn .elementor-button-icon, .btn .elementor-button-icon{
    padding:16px;
}
}
